import clsx from 'clsx';

import {
  bottom as bottomStyle,
  magnifier,
  rotatedBottomStyle,
} from './Magnifier.sty.js';
import { Magnifier } from './Magnifier.js';
import { useMagnifierPosition } from '../hooks/useMagnifierPosition.js';

export function BottomMagnifier(
  props: Readonly<{
    label: string;
    mouseX: number;
    offset: number;
    color: string;
    chartBounds?: DOMRect;
    isRotated?: boolean;
  }>,
) {
  const { label, mouseX, offset, color, chartBounds, isRotated } = props;

  const { magnifierPosition: left, magnifierRef } = useMagnifierPosition(
    mouseX,
    chartBounds?.left ?? 0,
    chartBounds?.right ?? 0,
    'horizontal',
    isRotated,
  );
  const top = (chartBounds?.bottom ?? 0) + offset;

  return (
    <Magnifier
      aria-label="bottom axis magnifier"
      ref={magnifierRef}
      className={clsx(magnifier, isRotated ? rotatedBottomStyle : bottomStyle)}
      style={{ top, left, backgroundColor: color }}
    >
      {label}
    </Magnifier>
  );
}
